use ethers::abi::{encode, Token};
use ethers::types::Bytes;

use crate::calldata::sel4;

pub fn build_gm() -> Bytes {
    Bytes::from(sel4("c0129d43"))
}

pub fn build_gn() -> Bytes {
    Bytes::from(sel4("3118f543"))
}

fn build_deploy(bytecode_hex: &str) -> Bytes {
    let bytecode = hex_to_bytes(bytecode_hex);
    let mut data = sel4("00774360");
    let encoded = encode(&[Token::Bytes(bytecode)]);
    data.extend_from_slice(&encoded);
    Bytes::from(data)
}

pub fn build_deploy_simple() -> Bytes {
    build_deploy(SIMPLE_BYTECODE)
}

pub fn build_deploy_token() -> Bytes {
    build_deploy(TOKEN_BYTECODE)
}

pub fn build_deploy_nft() -> Bytes {
    build_deploy(NFT_BYTECODE)
}

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    let hex = hex.trim_start_matches("0x");
    (0..hex.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap_or(0))
        .collect()
}

const SIMPLE_BYTECODE: &str = "";

const TOKEN_BYTECODE: &str = "";

const NFT_BYTECODE: &str = "";